function solve(grid) {
    const M = grid.length;
    if (M === 0) return 0;
    const N = grid[0].length;
    if (N === 0) return 0;

    // DP[i][j] will store a Set of all possible XOR sums reaching cell (i, j)
    // Initialize DP table
    const DP = Array(M).fill(0).map(() => Array(N).fill(0).map(() => new Set()));

    // Base case: Start cell (0, 0)
    DP[0][0].add(grid[0][0]);

    // Fill the first row (i=0)
    for (let j = 1; j < N; j++) {
        const currentValue = grid[0][j];
        // Only one way to reach (0, j): from (0, j-1)
        for (const xorSum of DP[0][j - 1]) {
            DP[0][j].add(xorSum ^ currentValue);
        }
    }

    // Fill the first column (j=0)
    for (let i = 1; i < M; i++) {
        const currentValue = grid[i][0];
        // Only one way to reach (i, 0): from (i-1, 0)
        for (const xorSum of DP[i - 1][0]) {
            DP[i][0].add(xorSum ^ currentValue);
        }
    }

    // Fill the rest of the DP table
    for (let i = 1; i < M; i++) {
        for (let j = 1; j < N; j++) {
            const currentValue = grid[i][j];

            // From Top (i-1, j)
            for (const xorSum of DP[i - 1][j]) {
                DP[i][j].add(xorSum ^ currentValue);
            }

            // From Left (i, j-1)
            for (const xorSum of DP[i][j - 1]) {
                DP[i][j].add(xorSum ^ currentValue);
            }
        }
    }

    // The result is the minimum value in DP[M-1][N-1]
    const finalXorSums = DP[M - 1][N - 1];

    let minXor = Infinity;
    for (const sum of finalXorSums) {
        if (sum < minXor) {
            minXor = sum;
        }
    }

    return minXor;
}

