    val N = grid[0].size
    if (N == 0) return 0L

    // DP[i][j] stores a MutableSet of all possible XOR sums reaching cell (i, j)
    val dp = Array(M) { Array(N) { mutableSetOf<Long>() } }

    // Base case: Start cell (0, 0)
    dp[0][0].add(grid[0][0])

    // Fill the first row (i=0)
    for (j in 1 until N) {
        val currentValue = grid[0][j]
        // Only one way to reach (0, j): from (0, j-1)
        for (xorSum in dp[0][j - 1]) {
            dp[0][j].add(xorSum xor currentValue)
        }
