    // Fill the first column (j=0)
    for (i in 1 until M) {
        val currentValue = grid[i][0]
        // Only one way to reach (i, 0): from (i-1, 0)
        for (xorSum in dp[i - 1][0]) {
            dp[i][0].add(xorSum xor currentValue)
        }
    }

    // Fill the rest of the DP table
    for (i in 1 until M) {
        for (j in 1 until N) {
            val currentValue = grid[i][j]

            // From Top (i-1, j)
            for (xorSum in dp[i - 1][j]) {
                dp[i][j].add(xorSum xor currentValue)
            }

            // From Left (i, j-1)
            for (xorSum in dp[i][j - 1]) {
                dp[i][j].add(xorSum xor currentValue)
            }
        }
    }

    // The result is the minimum value in DP[M-1][N-1]
    val finalXorSums = dp[M - 1][N - 1]

